assert("RELAY_INPUT branch exists", relayInputStart >= 0);
const relayInputEnd = relay.indexOf("// RELAY_OUTPUT", relayInputStart);
assert("RELAY_INPUT branch end found", relayInputEnd > relayInputStart);
const relayInputBlock = relay.slice(relayInputStart, relayInputEnd);
assert("RELAY_INPUT updates task ledger", relayInputBlock.includes("addRelayTaskInput(from, localPath)"));
assert("RELAY_INPUT uses relay group session", relayInputBlock.includes("const relayChatId = config.relay!.groupChatId;"));
assert("RELAY_INPUT no longer injects into owner private session", !relayInputBlock.includes("sessions.get(ownerChatId, ownerChatId)"));
assert("RELAY_INPUT sends silent meta to relay group", relayInputBlock.includes('session, prompt, { kind: "meta", silent: true }'));

assert("incoming delegate attachment records ledger", relay.includes('direction: "incoming"') && relay.includes("attachmentPath: localPath"));
assert("incoming delegate text records ledger", relay.includes("delegate from ${msg.from}") && relay.includes("injectRelayTaskNoticeToOwner("));
assert("incoming result closes outgoing ledger task", relay.includes('direction: "outgoing"') && relay.includes("resultSummary: r.summary"));

assert("outgoing relay delegates record ledger", runPrompt.includes('direction: "outgoing"') && runPrompt.includes("attachmentPath: session._lastUploadPath"));
assert("relay replies record incoming results", runPrompt.includes('direction: "incoming"') && runPrompt.includes("resultSummary: rr.payload.summary"));
assert("relay output files attach to ledger", runPrompt.includes("addRelayTaskOutput(rf.target, rf.path)"));

console.log("relay context ledger semantics OK");

// Local smoke test: verifies topic-rules helpers, the OR-match that used
// to live in mcp-memory.ts listFacts, and the new shard fast-path.
// Run from project root:
//   node scripts/check-topic-match.mjs
//
// Exits non-zero if shard vs OR-scan counts disagree — that would mean
// facts_Topic/<uid>/ is out of sync with the master log and rebuild is
// needed.
//
// userId 偵測順序：env MEMORY_USER_ID → MEMORY_DIR/.user-id → glob facts-*.md
import { readFile } from "node:fs/promises";
import { existsSync, readFileSync, readdirSync } from "node:fs";
import path from "node:path";
import {
  keywordsForTopic,
  classifyFact,
  topicKeywordHint,
} from "../dist/topic-rules.js";
import {
  readTopicFacts,
  listTopicShards,
  userShardDir,
} from "../dist/facts-store.js";

// 動態取得 MEMORY_DIR（與 config.ts 相同邏輯）
const MEMORY_DIR = process.env.MEMORY_DIR?.trim() || "F:\\AI\\AIMemory";

// 動態偵測 userId
function detectUserId(memoryDir) {
  // 1. env
  if (process.env.MEMORY_USER_ID) return Number(process.env.MEMORY_USER_ID);
  // 2. .user-id 檔案
  const userIdFile = path.join(memoryDir, ".user-id");
  if (existsSync(userIdFile)) {
    const content = readFileSync(userIdFile, "utf8").trim();
    if (/^\d+$/.test(content)) return Number(content);
  }
  // 3. glob facts-*.md
  const entries = readdirSync(memoryDir);
  for (const e of entries) {
    const m = e.match(/^facts-(\d+)\.md$/);
    if (m) return Number(m[1]);
  }
  throw new Error(
    `Cannot detect userId. Set MEMORY_USER_ID env or create ${userIdFile}`
  );
}

const userId = detectUserId(MEMORY_DIR);

console.log("=== helpers ===");
console.log("keywordsForTopic('bridge-token'):", keywordsForTopic("bridge-token"));
console.log("keywordsForTopic('BRIDGE-TOKEN'):", keywordsForTopic("BRIDGE-TOKEN"));
console.log("keywordsForTopic('nope'):", keywordsForTopic("nope"));
console.log("topicKeywordHint('scheduler'):", topicKeywordHint("scheduler"));
console.log("");

const raw = (await readFile(path.join(MEMORY_DIR, `facts-${userId}.md`), "utf8")).trim();
const all = raw
  .split(/\r?\n/)
  .map((l) => l.replace(/^\s*-\s*\[[^\]]+\]\s*/, "").trim())
  .filter(Boolean);
console.log("=== dataset ===");
console.log("total facts:", all.length);
console.log("shardDir:", userShardDir(userId));
console.log("shardDir exists:", existsSync(userShardDir(userId)));
console.log("");

const shards = listTopicShards(userId);
console.log("=== shards on disk ===");
if (shards.length === 0) {
  console.log("(no shards — run rebuild-topic-shards.mjs first)");
} else {
  for (const s of shards) console.log(`  ${s.topic}.md  (${s.count})`);
}
console.log("");

const topics = [
  "bridge-token",
  "scheduler",
  "uk-slot",
  "windows-ops",
  "user-pref",
  "bridge-core",
];

console.log("=== shard vs classify parity ===");
// Shard writes use classifyFact (first-match-wins), so each fact lives in
// exactly one shard. OR-scan over keywords is a superset because one fact
// can match multiple topics. The meaningful check is:
//   shard(topic).length === classify-histogram(topic)
// for every topic. OR-scan totals are printed for info only.
const histogram = new Map();
for (const f of all) {
  const t = classifyFact(f);
  histogram.set(t, (histogram.get(t) || 0) + 1);
}

let mismatches = 0;
for (const topic of topics) {
  const kws = keywordsForTopic(topic) ?? [];
  const lowered = kws.map((k) => k.toLowerCase());
  const orHits = all.filter((s) => {
    const sl = s.toLowerCase();
    return lowered.some((k) => sl.includes(k));
  });
  const shardHits = readTopicFacts(userId, topic);
  const expected = histogram.get(topic) ?? 0;
  const ok = shardHits.length === expected ? "ok" : "MISMATCH";
  if (shardHits.length !== expected) mismatches++;
  console.log(
    `topic=${topic.padEnd(12)} shard=${String(shardHits.length).padStart(2)} ` +
      `classify=${String(expected).padStart(2)} ` +
      `or-scan=${String(orHits.length).padStart(2)}  ${ok}`
  );
  for (const h of shardHits.slice(0, 1)) console.log("    sample:", h.slice(0, 90));
}
console.log("");
console.log(
  "(or-scan >= classify is expected — OR matches facts that belong to other topics too)"
);
console.log("");

console.log("=== classify histogram (should match shard counts above) ===");
console.log(
  Object.fromEntries(
    [...histogram.entries()].sort((a, b) => b[1] - a[1])
  )
);

if (mismatches > 0) {
  console.error(
    `\nFAIL: ${mismatches} topic(s) shard count != classify count — run rebuild-topic-shards.mjs`
  );
  process.exit(1);
}
console.log("\nOK: shard counts match classify histogram for all tested topics");

